// Header.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import AppBar from '@material-ui/core/AppBar';
import Toolbar from '@material-ui/core/Toolbar';
import Typography from '@material-ui/core/Typography';
import IconButton from '@material-ui/core/IconButton';
import MenuIcon from '@material-ui/icons/Menu';
import Drawer from '@material-ui/core/Drawer';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import SearchIcon from '@material-ui/icons/Search';
import InputBase from '@material-ui/core/InputBase';
import { alpha, makeStyles } from '@material-ui/core/styles';
import { useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import DrawerMenu from './Menu/DrawerMenu';
import SubMenu from './Menu/SubMenu';
import UserActions from './Menu/UserActions';
import LanguageToggle from './Menu/LanguageToggle';
import useStyles from './styles';
import { getPlayers } from '../../actions/players';

const Header = ({ isAuthenticated, logout }) => {
  const category = useSelector((state) => state.menus);
  const classes = useStyles();
  const dispatch = useDispatch();
  const history = useNavigate();

  const [drawerOpen, setDrawerOpen] = useState(false);

  useEffect(() => {
    console.log("categories: ", category);
  }, [category]);

  const toggleDrawer = (open) => (event) => {
    if (
      event.type === 'keydown' &&
      (event.key === 'Tab' || event.key === 'Shift')
    ) {
      return;
    }
    setDrawerOpen(open);
  };

  const listPlayer = (e, mainMenu, sub) => {
    e.preventDefault();
    const categories = [mainMenu, sub];
    dispatch(getPlayers({ name: categories.join(',') }));
    history(`/players/search?searchQuery=${categories.join(',')}`, {
      redirect: true,
    });
  };

  const filteredCategories = isAuthenticated
    ? category
    : category.filter((menu) => menu.subMenu.length > 0);

  const menuItems = filteredCategories;

  return (
    <div className={classes.root}>
      <AppBar position="static" className={classes.background}>
        <Toolbar component="div">
          <IconButton
            edge="start"
            color="inherit"
            aria-label="menu"
            onClick={toggleDrawer(true)}
          >
            <MenuIcon />
          </IconButton>

          <Typography
            variant="h6"
            color="inherit"
            className={classes.title}
            component={Link}
            to="./../"
          >
            Norske Fotballdrakter
          </Typography>

          <div className={classes.search}>
            <div className={classes.searchIcon}>
              <SearchIcon />
            </div>
            <InputBase
              placeholder="Search…"
              classes={{
                root: classes.inputRoot,
                input: classes.inputInput,
              }}
              inputProps={{ 'aria-label': 'search' }}
            />
          </div>
          <LanguageToggle />
        </Toolbar>
      </AppBar>

      <Drawer anchor="left" open={drawerOpen} onClose={toggleDrawer(false)}>
        <List>
          {/* Add your big menu items here */}
          <ListItem button>
            <ListItemText primary="Menu Item 1" />
          </ListItem>
          <ListItem button>
            <ListItemText primary="Menu Item 2" />
          </ListItem>
        </List>
      </Drawer>
    </div>
  );
};

export default Header;
